arguments.command:
cat << 'EOF' > /tmp/stackalloc_nint.cs
Span<nint> signed = stackalloc nint[4];
Span<nuint> unsigned = stackalloc nuint[4];

for (int i = 0; i < 4; i++)
{
    signed[i] = i * 10;
    unsigned[i] = (nuint)(i * 20);
}

Console.WriteLine($"nint size: {sizeof(nint)} bytes");
Console.WriteLine($"signed: [{signed[0]}, {signed[1]}, {signed[2]}, {signed[3]}]");
Console.WriteLine($"unsigned: [{unsigned[0]}, {unsigned[1]}, {unsigned[2]}, {unsigned[3]}]");
EOF
dotnet run --project /tmp/stackalloc_nint.cs 2>&1

